import React from 'react'
import styles from './nav-bar.module.css';
import NavButton from '../nav-button';

const NavBar = () => {
  return (
    <div className={styles.nav__bar}>
        <NavButton text="Discovery" href="#">
            <img src="/images/ChevronDown.svg" alt="icon" />
        </NavButton>
        <NavButton text="About" href="#" />
        <NavButton text="Contact us" href="#" />
    </div>
  )
}

export default NavBar;
